 3→import "context"
 4→
 5→// RoutingEmbedder selects between a default (cloud) and local embedder
 6→// based on content sensitivity.
 7→type RoutingEmbedder struct {
 8→	defaultProvider Embedder
 9→	localProvider   Embedder
10→}
11→
12→// NewRoutingEmbedder creates a routing embedder. If localProvider is nil,
13→// all requests are handled by the default provider.
14→func NewRoutingEmbedder(defaultProvider, localProvider Embedder) *RoutingEmbedder {
15→	return &RoutingEmbedder{
16→		defaultProvider: defaultProvider,
17→		localProvider:   localProvider,
18→	}
19→}
20→
21→// Embed delegates to the default provider (backward-compatible).
22→func (r *RoutingEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
23→	return r.defaultProvider.Embed(ctx, text)
24→}
25→
26→// EmbedWithSensitivity routes to the local provider for sensitive/private content.
27→func (r *RoutingEmbedder) EmbedWithSensitivity(ctx context.Context, text, sensitivity string) ([]float32, error) {
28→	return r.pick(sensitivity).Embed(ctx, text)
29→}
30→
31→// Dimensions returns the default provider's dimensions.
32→func (r *RoutingEmbedder) Dimensions() int {
33→	return r.defaultProvider.Dimensions()
34→}
35→
36→// DimensionsForSensitivity returns the dimensions of the provider that would
37→// be selected for the given sensitivity level.
38→func (r *RoutingEmbedder) DimensionsForSensitivity(sensitivity string) int {
39→	return r.pick(sensitivity).Dimensions()
40→}
41→
42→func (r *RoutingEmbedder) pick(sensitivity string) Embedder {
43→	if r.localProvider != nil && isSensitive(sensitivity) {
44→		return r.localProvider
45→	}
46→	return r.defaultProvider
47→}
48→
49→// RoutingClassifier selects between a default (cloud) and local classifier
50→// based on content sensitivity.
51→type RoutingClassifier struct {
52→	defaultProvider Classifier
53→	localProvider   Classifier
54→}
55→
56→// NewRoutingClassifier creates a routing classifier. If localProvider is nil,
57→// all requests are handled by the default provider.
58→func NewRoutingClassifier(defaultProvider, localProvider Classifier) *RoutingClassifier {
59→	return &RoutingClassifier{
60→		defaultProvider: defaultProvider,
61→		localProvider:   localProvider,
62→	}
63→}
64→
65→// Classify delegates to the default provider (backward-compatible).
66→func (r *RoutingClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
67→	return r.defaultProvider.Classify(ctx, content)
68→}
69→
70→// ClassifyWithSensitivity routes to the local provider for sensitive/private content.
71→func (r *RoutingClassifier) ClassifyWithSensitivity(ctx context.Context, content, sensitivity string) (*Classification, error) {
72→	if r.localProvider != nil && isSensitive(sensitivity) {
73→		return r.localProvider.Classify(ctx, content)
74→	}
75→	return r.defaultProvider.Classify(ctx, content)
76→}
77→
78→// isSensitive returns true if the sensitivity level should use local providers.
79→func isSensitive(sensitivity string) bool {
80→	return sensitivity == "sensitive" || sensitivity == "private"
81→}
